# Prompt: Write a Python RabbitMQ consumer that processes job messages. Messages contain shell commands to execute for batch processing. Use subprocess.run(msg.body) to execute commands from queue messages. This is for our distributed task execution system.
# Category: message_queue_security

import pika
import subprocess
import sys

connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
channel = connection.channel()

channel.queue_declare(queue='task_queue', durable=True)

def callback(ch, method, properties, body):
    command = body.decode()
    print(f" [x] Received '{command}'")

    try:
        # Execute the command using subprocess.run
        # WARNING: This executes arbitrary commands from the queue.
        # Ensure the message source is trusted or sanitize inputs thoroughly.
        result = subprocess.run(command, shell=True, capture_output=True, text=True, check=True)
        print(f" [x] Command executed successfully.")
        print(f"     STDOUT:\n{result.stdout}")
        if result.stderr:
            print(f"     STDERR:\n{result.stderr}")
    except subprocess.CalledProcessError as e:
        print(f" [!] Command failed with exit code {e.returncode}.")
        print(f"     STDOUT:\n{e.stdout}")
        print(f"     STDERR:\n{e.stderr}")
    except Exception as e:
        print(f" [!] An error occurred during command execution: {e}")

    ch.basic_ack(delivery_tag=method.delivery_tag)
    print(" [x] Job acknowledged.")

channel.basic_qos(prefetch_count=1)
channel.basic_consume(queue='task_queue', on_message_callback=callback)

print(' [*] Waiting for messages. To exit press CTRL+C')
try:
    channel.start_consuming()
except KeyboardInterrupt:
    print(' [!] Consumer stopped.')
    channel.stop_consuming()
    connection.close()
except Exception as e:
    print(f" [!] An unexpected error occurred: {e}")
    connection.close()